using UnityEngine;

// This is a conceptual lesson — no code required!
// But here's a sample game manager to get started

public class GameDesignDocument : MonoBehaviour
{
    public string gameTitle = "My First Game";
    public string genre = "2D Platformer";
    public string targetPlatform = "PC, WebGL";
    public string estimatedPlaytime = "10-15 minutes";

    void Start()
    {
        Debug.Log("=== Game Design Document ===");
        Debug.Log("Title: " + gameTitle);
        Debug.Log("Genre: " + genre);
        Debug.Log("Platform: " + targetPlatform);
        Debug.Log("Estimated Playtime: " + estimatedPlaytime);
        Debug.Log("\n--- Core Mechanic ---");
        Debug.Log("The player moves, jumps, and collects items to progress.");
        Debug.Log("\n--- Story Summary ---");
        Debug.Log("A hero must traverse obstacles, defeat enemies, and reach the goal.");
        Debug.Log("\n--- Target Audience ---");
        Debug.Log("Casual gamers, platformer fans, beginners");
        Debug.Log("\n✅ Game Design Document drafted!");
    }
}
